import yaml
import os

def generate_config(env='development'):
    config = {
        'metadata': {
            'name': 'dynamic-agent',
            'version': '1.0.0'
        },
        'settings': {
            'model': 'gemini-1.5-flash' if env == 'development' else 'gemini-1.5-pro',
            'temperature': 0.1 if env == 'development' else 0.4,
            'max_tokens': 2048
        }
    }

    with open('agent.yaml', 'w') as f:
        yaml.safe_dump(config, f, default_flow_style=False)
    print(f"Created config for {env} environment.")

if __name__ == '__main__':
    env_mode = os.getenv('AGENT_ENV', 'development')
    generate_config(env_mode)
